// Maps each portfolioData.js fund's `assetClass` label to the MANAGER_LISTS bucket it
// should pull swap-in alternatives from. Every assetClass value currently used across all
// 4 models (corePrivate, selectLiquidity, traditional, focusedB) is covered here.
export const ASSET_CLASS_TO_SLOT = {
  "US Large Cap Core":     "usLargeCore",
  "US Large Cap Value":    "usLargeValue",
  "US Large Cap Growth":   "usLargeGrowth",
  "US Mid Cap":            "usMidCap",
  "US Small Cap":          "usSmallCap",
  "Intl Developed Value":  "intlDevValue",
  "Intl Developed Growth": "intlDevGrowth",
  "Emerging Markets":      "emergingMarkets",
  "Core/Muni Bonds":       "usCoreMuni",
  "Short-Term Fixed":      "usShortTermFixed",
  "US TIPS":               "usTips",
  "Private Equity":           "privateEquity",
  "Real Estate":              "realEstate",
  "Hedge Funds":              "hedgeFunds",
  "Hedged Equity":            "hedgedEquity",
  "Real Assets":              "realAssets",
  "Real Assets & Other Alts": "realAssets",
  "Private Credit":           "privateCredit",
  "Diversified Alternatives": "diversifiedAlts",
  "Cash":                     "cash",
};

const GENERIC_TICKERS = new Set(["", "N/A", "SMA", "CUSTOM", "UMA ONLY!"]);

function normalizeName(name) {
  return (name || "")
    .replace(/^\[\s*pass\w*\s*[\]}]\s*/i, "") // strip leading [Passive]/[Passve]/[Passive} prefix
    .replace(/\s*\([^)]*\)\s*$/, "")            // strip trailing "(TICKER)"
    .replace(/\u00A0/g, " ")
    .trim()
    .toLowerCase();
}

function isCurrentFund(candidate, currentFund) {
  if (!currentFund) return false;
  const candTicker = (candidate.ticker || "").trim().toUpperCase();
  const currTicker = (currentFund.ticker || "").trim().toUpperCase();
  if (candTicker && currTicker && !GENERIC_TICKERS.has(candTicker) && !GENERIC_TICKERS.has(currTicker)) {
    return candTicker === currTicker;
  }
  // Generic/placeholder tickers (SMA, N/A, CUSTOM) can't disambiguate funds, so fall back
  // to comparing manager/fund names instead.
  const currName = currentFund.fullName || currentFund.name || "";
  return normalizeName(candidate.name) === normalizeName(currName);
}

/**
 * Suggests up to 2 alternative funds for a given portfolio fund line, drawn from the same
 * asset-class manager list the fund itself belongs to. This directly reflects the advisor's
 * stated ranking criteria:
 *   - risk profile fit: candidates are restricted to the SAME asset-class bucket as the
 *     current fund (e.g. a "US Large Cap Value" slot only ever offers other "US Large Cap
 *     Value" managers), so a swap never changes the style/factor exposure the allocation
 *     was built around.
 *   - fee / tax efficiency: within that bucket, candidates are ranked by fee ascending —
 *     lower-fee funds are also generally the more tax-efficient ones (passive index
 *     funds/ETFs in this list versus actively-managed mutual funds).
 *   - passive vs. active choice: the two suggestions returned are the cheapest eligible
 *     PASSIVE fund and the cheapest eligible ACTIVE fund, so the advisor always sees one of
 *     each rather than two near-identical options.
 * `dollarAllocated` (optional) excludes any candidate whose minimum investment exceeds the
 * dollars actually allocated to this line.
 */
export function getFundAlternatives(fund, dollarAllocated = Infinity) {
  if (!fund || !fund.assetClass) return [];
  const slot = ASSET_CLASS_TO_SLOT[fund.assetClass];
  const list = slot ? MANAGER_LISTS[slot] : null;
  if (!list || list.length === 0) return [];

  const eligible = list.filter(f => {
    if (isCurrentFund(f, fund)) return false;
    const min = Number(f.minimum) || 0;
    return min <= dollarAllocated;
  });
  if (eligible.length === 0) return [];

  const byFee = [...eligible].sort((a, b) => (a.fee ?? Infinity) - (b.fee ?? Infinity));
  const passiveBest = byFee.find(f => f.passive);
  const activeBest = byFee.find(f => !f.passive);

  const picks = [];
  for (const candidate of [passiveBest, activeBest]) {
    if (candidate && !picks.some(p => p.name === candidate.name)) picks.push(candidate);
  }
  // Backfill with next-cheapest options if a passive or active match wasn't available
  for (const candidate of byFee) {
    if (picks.length >= 2) break;
    if (!picks.some(p => p.name === candidate.name)) picks.push(candidate);
  }
  return picks.slice(0, 2);
}

/** Returns the full eligible manager list for a fund's asset class, cheapest first —
 *  used if the advisor wants to see every option rather than just the top 2 suggestions. */
export function getFullManagerList(fund, dollarAllocated = Infinity) {
  if (!fund || !fund.assetClass) return [];
  const slot = ASSET_CLASS_TO_SLOT[fund.assetClass];
  const list = slot ? MANAGER_LISTS[slot] : null;
  if (!list) return [];
  return list
    .filter(f => (Number(f.minimum) || 0) <= dollarAllocated)
    .sort((a, b) => (a.fee ?? Infinity) - (b.fee ?? Infinity));
}

/** Returns the cheapest publicly-tradable PASSIVE ticker for a portfolioData.js
 *  `assetClass`, or "" if that asset class has no public passive proxy (e.g. Hedge
 *  Funds, Private Equity, Private Credit are non-tradable by nature). Used by the
 *  portfolio backtest (backtest.js + App.jsx) to substitute a low-cost public proxy
 *  for any fund line whose actual vehicle (SMA/private fund) has no price history,
 *  so that sleeve can still be represented in a historical backtest instead of being
 *  silently dropped. */
export function getCheapestPassiveTicker(assetClass) {
  const slot = ASSET_CLASS_TO_SLOT[assetClass];
  const list = slot ? MANAGER_LISTS[slot] : null;
  if (!list) return "";
  const passive = list
    .filter(f => f.passive && isTradableTicker(f.ticker))
    .sort((a, b) => (a.fee ?? Infinity) - (b.fee ?? Infinity));
  return passive[0]?.ticker || "";
}

function isTradableTicker(ticker) {
  const t = String(ticker || "").trim().toUpperCase();
  return !!t && !GENERIC_TICKERS.has(t);
}
